option.value:
/* Starfield Background */
.starfield {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: #000011;
    z-index: -1;
    overflow: hidden;
}

.star {
    position: absolute;
    background: white;
    border-radius: 50%;
    animation: twinkle 3s infinite;
}

/* Random sizes for stars */
.star.size1 { width: 1px; height: 1px; }
.star.size2 { width: 2px; height: 2px; }
.star.size3 { width: 3px; height: 3px; }

/* Blinking/Twinkling animation */
@keyframes twinkle {
    0%, 100% { opacity: 0.3; }
    50% { opacity: 1; }
}

/* Variation in animation timing */
.star:nth-child(1) { animation-delay: 0s; }
.star:nth-child(2) { animation-delay: 0.3s; }
.star:nth-child(3) { animation-delay: 0.6s; }
.star:nth-child(4) { animation-delay: 0.9s; }
.star:nth-child(5) { animation-delay: 1.2s; }
.star:nth-child(6) { animation-delay: 1.5s; }
.star:nth-child(7) { animation-delay: 1.8s; }
.star:nth-child(8) { animation-delay: 2.1s; }
.star:nth-child(9) { animation-delay: 2.4s; }
.star:nth-child(10) { animation-delay: 2.7s; }
.star:nth-child(n+11) { 
    animation-delay: calc((var(--index, 1) * 0.3s) % 3s);
}

body {
    background: #000011;
}


.menu {
    width: 100%;
    display: flex;
    flex-wrap: wrap;
}


.menu div {
    flex: 1;
   /* background-color: rgb(0 255 241 / 49%);*/
    background: linear-gradient(-15deg, rgb(26 0 255 / 75%), rgb(0 255 241 / 0.49));
    border: 0.1em solid #71a7e4;
    min-width: 8em;
    margin: 0.5em;
    padding: 0.5em;
    border-radius: 0.5em;
    box-shadow: 0 0 1em rgb(255 255 255 / 0.41);
}

.menu div a {
    text-decoration: none;
    color: wheat;
    font-family: 'Courier New', Courier, monospace;
    font-weight: bold;
    text-align: center;
    display: block;
    text-shadow: 0 0 1em rgb(9 0 0 / 0.41);
}

.menu div.aktiv {
    background: linear-gradient(-15deg, rgb(25 0 205 / 0.75), rgb(0 216 201 / 0.49));
    scale: 0.99;
    box-shadow: 0 0 1em rgb(27 27 27 / 0.41);
}

h1 {
    clear: left;
    font-family: 'Times New Roman', Times, serif;
    color: #f6e8c9;
    text-shadow: 0 0 1em rgb(255 255 255 / 0.41);
}

.inhalt {
    display: grid;
    grid-template-columns:
   repeat(auto-fit, minmax(20rem, 1fr));

}

.absatz {
    margin: 0.5em;
    padding: 1em;
    /*background-color: rgb(17 47 83 / 0.33);*/
    color: white;
    border-radius: 0.5em;
rgb(95 26 133 / 0.38));
}
border: 0.1em solid #23ccd2b0;
    font-family: sans-serif;
    box-shadow: 0 0 1em rgb(255 255 255 / 0.41);
background: linear-gradient(
            135deg,
            rgb(45 110 1 / 0.4),

.absatz.gruen {
    background: linear-gradient(
            135deg,
            rgb(125 255 0 / 0.4),
            rgb(95 26 133 / 0.38));
    border: 0.1em solid #00ff00;
}

.absatz.blau {
    background: linear-gradient(
            135deg,
            rgb(20 67 168),
            rgb(95 26 133 / 0.38));
    border: 0.1em solid #0000ff;
}

.absatz.gelb {
    background: linear-gradient(
            135deg,
            rgb(204 204 7 / 0.4),
            rgb(95 26 133 / 0.38));
    border: 0.1em solid #ffff00;
}

.absatz.rot {
    background: linear-gradient(
            135deg,
            rgb(255 0 0 / 0.4),
            rgb(95 26 133 / 0.38));
    border: 0.1em solid #ff0000;
}

.absatz.schwarz {
    background: linear-gradient(
            135deg,
            rgb(0 0 0 / 0.91),
            rgb(95 26 133 / 0.38));
    border: 0.1em solid #ffffff;
}

.absatz a {
    color: white;
}

.rund {
    border-radius: 50%;
}



.quelle{
    color: rgb(255 255 255 / 0.8);
    font-family: sans-serif;
    font-size: 0.8em;
    margin-left: 1em;
}

.foto {
    border-radius: 0.5em;
}

.bild_container {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(20rem, 1fr));
    grid-gap: 1em;
    padding: 0;
}

@media (min-width: 60em) {
    .bild_container {
        grid-template-columns: repeat(auto-fit, minmax(20rem, 1fr));
    }
}

.bild_container img {
    height: 100%;
    width: 100%;
    object-fit: cover;
    border: .2em solid green;
}

.bild_container img.diagramm {
    height: auto;
    border-radius: 0.5em;
    object-fit: contain;
    border: none;
}

